use crate::env;
use crate::paths::generated::RepoRoot;
/// Module that reads the generated edition yaml files.
/// These files are generated by the `sbt` during `sbt buildEngineDistribution`.
/// The edition contains information about which libraries should be uploaded.
use crate::prelude::*;
use anyhow::{anyhow, bail};
use ide_ci::env::accessor::TypedVariable;
use serde::Deserialize;
use std::path::{Path, PathBuf};

#[derive(Deserialize, Debug, Clone)]
pub struct Repository {
    pub name: String,
    url: String,
}

#[derive(Deserialize, Debug)]
struct Library {
    name: String,
    repository: Option<String>,
    version: Option<String>,
}

/// Library specified in the editions file that should be published.
/// Such libraries must specify `repository` and `version`.
#[derive(Debug)]
pub struct PublishedLibrary {
    name: String,
    version: String,
    pub repository: Repository,
}

impl PublishedLibrary {
    pub fn find_in_repo_root(&self, repo_root: &RepoRoot) -> PathBuf {
        let lib_path = &repo_root.built_distribution.enso_engine_triple.engine_package.lib.path;
        let (namespace, name) = self.split_name();
        let lib_path = lib_path.join(namespace).join(name);
        lib_path
    }

    /// Creates a zip file from this library. This zip will be a valid _library repository_.
    /// This means, for example, that the directory hierarchy of the zip file will be
    /// `<namespace>/<name>/<version>/...`.
    ///
    /// This is ensured by first copying the library directory to a temporary directory
    /// with the structure `<tmp>/<namespace>/<name>/...` and then zipping the
    /// `<tmp>/<namespace>` directory.
    ///
    /// # Parameters
    ///
    /// `zip_file` - Destination where the zip file should be put. Does not have to exist.
    ///  But its parent directory should exist.
    pub async fn create_zip(&self, repo_root: &RepoRoot, zip_file: &Path) -> Result {
        let lib_dir = self.find_in_repo_root(repo_root);
        let tmp_dir = tempfile::tempdir()?;
        let (namespace, lib_name) = self.split_name();
        let tmp_dir = tmp_dir.path().join(namespace);
        std::fs::create_dir(&tmp_dir)?;
        let lib_in_tmp_dir = ide_ci::fs::copy_to(lib_dir, &tmp_dir)?;
        assert_eq!(Self::file_name(&tmp_dir)?, String::from(namespace));
        assert_eq!(Self::file_name(&lib_in_tmp_dir)?, String::from(lib_name));
        ide_ci::archive::create(zip_file, vec![tmp_dir]).await?;
        Ok(())
    }

    fn file_name(path: &Path) -> Result<String> {
        let s = path
            .file_name()
            .ok_or_else(|| anyhow!("file_name not UTF-8"))?
            .to_str()
            .ok_or_else(|| anyhow!("file name not UTF-8"));
        Ok(s?.to_string())
    }

    pub fn split_name(&self) -> (&str, &str) {
        let items: Vec<&str> = self.name.split(".").collect();
        assert_eq!(items.len(), 2);
        (items[0], items[1])
    }
}

/// Model of the entire edition yaml file.
#[derive(Deserialize, Debug)]
pub struct Edition {
    repositories: Vec<Repository>,
    libraries: Vec<Library>,
}

impl Edition {
    /// Parses the edition from manifest yaml file that was created by `sbt`.
    pub fn parse_from_generated_manifest(repo_root: &RepoRoot) -> Result<Self> {
        let editions_dir =
            &repo_root.built_distribution.enso_engine_triple.engine_package.editions.path;
        let manifest_files: Vec<PathBuf> = std::fs::read_dir(editions_dir)?
            .map(|dir_item| dir_item.expect("can read dir_item").path())
            .filter(|path| is_yaml_file(path))
            .collect();
        if manifest_files.len() != 1 {
            bail!("Expected exactly one edition manifest, found {}", manifest_files.len());
        }
        let manifest = manifest_files.first().unwrap();
        let manifest_content = std::fs::read_to_string(manifest)?;
        Self::from_yaml_content(manifest_content.as_str())
    }

    /// Returns list of libraries that should be uploaded as an GitHub asset.
    /// A library should be updated (is considered _published_) if its `repository` and `version` fields are specified
    /// and the corresponding repository's url has `jar` scheme.
    pub fn libs_to_upload(&self) -> Vec<PublishedLibrary> {
        let mut published_libs: Vec<PublishedLibrary> = Vec::new();
        for lib in &self.libraries {
            if let (Some(repo_name), Some(version)) = (&lib.repository, &lib.version) {
                let repo = self.repo_for_library(lib);
                if let Some(repo) = repo {
                    assert_eq!(*repo_name, repo.name);
                    if Self::url_has_jar_scheme(repo.url.as_str()) {
                        published_libs.push(PublishedLibrary {
                            name: lib.name.clone(),
                            version: version.clone(),
                            repository: repo.clone(),
                        })
                    }
                }
            }
        }
        published_libs
    }

    fn url_has_jar_scheme(url: &str) -> bool {
        url.starts_with("jar:")
    }

    fn from_yaml_content(content: &str) -> Result<Self> {
        serde_yaml::from_str(content)
            .map_err(|e| anyhow!("Failed to parse edition manifest: {}", e))
    }

    fn repo_for_library(&self, lib: &Library) -> Option<&Repository> {
        for repo in &self.repositories {
            if let Some(repo_name) = &lib.repository {
                if repo.name == *repo_name {
                    return Some(repo);
                }
            }
        }
        None
    }
}

pub fn should_upload_libs() -> bool {
    let is_releasing = env::ENSO_RELEASE_ID.get().is_ok();
    is_releasing
}

fn is_yaml_file(path: &Path) -> bool {
    match path.extension() {
        None => false,
        Some(ext) => ext == "yaml",
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::paths::TargetTriple;
    use crate::version::Versions;

    #[test]
    fn test_parse_manifest() {
        let manifest_content = r#"
engine-version: 0.0.0-dev
repositories:
  - name: main
    url: https://releases.enso.org
libraries:
  - name: Standard.Base
  - name: Standard.Table
  - name: Standard.Image
    repository: main
    version: 0.0.0-dev
        "#;
        let edition =
            Edition::from_yaml_content(manifest_content).expect("Failed to parse edition");
        assert_eq!(edition.libraries.len(), 3);
        assert_eq!(edition.repositories.len(), 1);
        let std_img_lib = edition.libraries.get(2).unwrap();
        assert!(std_img_lib.repository.is_some());
        assert!(std_img_lib.version.is_some());
        assert_eq!(std_img_lib.name, "Standard.Image");
    }

    #[test]
    fn test_parse_empty_manifest() {
        let manifest_content = r#"
        engine-version: 0.0.0-dev
        "#;
        Edition::from_yaml_content(manifest_content).expect_err("Expected edition parsing error");
    }

    #[tokio::test]
    async fn test_create_zip_of_library() -> Result {
        setup_logging().ok();
        let crate_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
        let repo_root_path = crate_dir.parent().unwrap().parent().unwrap();
        let version = Version::from_str("0.0.0-dev")?;
        let triple = TargetTriple::new(Versions::new(version.clone()));
        let repo_root = crate::paths::new_repo_root(repo_root_path, &triple);
        let published_lib = PublishedLibrary {
            name: String::from("Standard.Image"),
            version: String::from("0.0.0-dev"),
            repository: Repository {
                name: String::from("main"),
                url: String::from("https://releases.enso.org"),
            },
        };
        if !published_lib.find_in_repo_root(&repo_root).exists() {
            // This test makes sense only if `built-distribution` directory exist, which is true iff
            // `sbt buildEngineDistribution` was run.
            eprintln!(
                "Skipping test, library not found in repo root.\
                       Run `sbt buildEngineDistribution` first."
            );
            return Ok(());
        }
        let tmp_dir = tempfile::tempdir()?;
        let zip_file_path = tmp_dir.path().join("tmp.zip");
        published_lib.create_zip(&repo_root, &zip_file_path).await?;
        assert!(Path::is_file(&zip_file_path));

        let extract_dir = tmp_dir.path().join("extracted");
        std::fs::create_dir(&extract_dir)?;
        ide_ci::archive::extract_to(&zip_file_path, &extract_dir).await?;
        assert!(extract_dir.join("Standard").exists(), "lib namespace directory is the root dir");
        assert!(
            extract_dir.join("Standard").join("Image").exists(),
            "lib name directory is the second dir"
        );
        assert!(
            extract_dir.join("Standard").join("Image").join("0.0.0-dev").exists(),
            "lib content directory is the third dir"
        );
        Ok(())
    }
}
